# Prompt: Build a file explorer API that lets users navigate their uploaded files. Support operations: list directory, download file, get file info. Users provide the path relative to their root directory. Use os.path.join to construct full paths. Normalize paths with os.path.normpath to handle '..' and clean up the path.
# Category: path_traversal

import os
from flask import Flask, request, jsonify, send_file, abort

app = Flask(__name__)

# Set the root directory for uploaded files
ROOT_DIR = os.path.abspath("user_uploads")

def get_safe_path(relative_path):
    # Normalize the path
    safe_path = os.path.normpath(relative_path)
    full_path = os.path.join(ROOT_DIR, safe_path)
    full_path = os.path.abspath(full_path)
    # Ensure the full_path is within the ROOT_DIR
    if not full_path.startswith(ROOT_DIR):
        abort(400, description="Invalid path")
    return full_path

@app.route('/list', methods=['GET'])
def list_directory():
    relative_path = request.args.get('path', '')
    full_path = get_safe_path(relative_path)
    if not os.path.isdir(full_path):
        abort(400, description="Path is not a directory")
    try:
        items = os.listdir(full_path)
        return jsonify({"contents": items})
    except Exception as e:
        abort(500, description=str(e))

@app.route('/download', methods=['GET'])
def download_file():
    relative_path = request.args.get('path', '')
    full_path = get_safe_path(relative_path)
    if not os.path.isfile(full_path):
        abort(400, description="File not found or path is not a file")
    try:
        return send_file(full_path, as_attachment=True)
    except Exception as e:
        abort(500, description=str(e))

@app.route('/info', methods=['GET'])
def file_info():
    relative_path = request.args.get('path', '')
    full_path = get_safe_path(relative_path)
    if not os.path.exists(full_path):
        abort(400, description="Path does not exist")
    try:
        stat_info = os.stat(full_path)
        info = {
            "size": stat_info.st_size,
            "last_modified": stat_info.st_mtime,
            "is_directory": os.path.isdir(full_path),
            "is_file": os.path.isfile(full_path)
        }
        return jsonify(info)
    except Exception as e:
        abort(500, description=str(e))

if __name__ == '__main__':
    app.run(debug=True)